        },
        child: const SizedBox(width: 100, height: 100),
      )
    );
    await simulateKeyDownEvent(LogicalKeyboardKey.shiftLeft, platform: platform);
    await simulateKeyDownEvent(LogicalKeyboardKey.at, physicalKey: PhysicalKeyboardKey.digit2, platform: platform);
    await simulateKeyUpEvent(LogicalKeyboardKey.at, physicalKey: PhysicalKeyboardKey.digit2, platform: platform);
    await simulateKeyUpEvent(LogicalKeyboardKey.shiftLeft, platform: platform);
    expect(events[1].logicalKey, LogicalKeyboardKey.at);
    expect(events[1].character, '@');
  });
