issues.body:
### Steps to reproduce

1. Run the sample code on a physical iOS device
2. Using a Korean keyboard type "ㅅㅛ"
3. Check the logs

### Expected results

The following deletion delta should be generated:

```dart
TextEditingDeltaDeletion(
  oldText: '. ㅅ',
  deletedRange: TextRange(start: 2, end: 3),
  selection: TextSelection.collapsed(
    offset: 2,
    affinity: TextAffinity.downstream,
  ),
  composing: TextRange(start: -1, end: -1),
)
```

### Actual results

The following deletion delta is reported (the deleted range start at offset 1 instead of 2):

```dart
TextEditingDeltaDeletion(
  oldText: '. ㅅ',
  deletedRange: TextRange(start: 1, end: 3),
  selection: TextSelection.collapsed(
    offset: 2,
    affinity: TextAffinity.downstream,
  ),
  composing: TextRange(start: -1, end: -1),
)
```

Background: In the super_editor package, we always send the text editing value to the IME prepended with the string `". "`. We do this to detect the user pressing the delete button at the beginning of the text, because pressing the delete button at the beginning of the editing value doesn't report anything. The `". "` is invisible to the user and when we receive a deletion of the space after the `.`, we consider that the user is pressing the delete button at the beginning of the text. This is used to merge the currently selected paragraph with the previous paragraph. The reported deltas are deleting the invisible characters and then generating a space insertion at an invalid position.


Here's all the deltas reported by Flutter:

First batch:

```dart
[
  TextEditingDeltaInsertion(
    oldText: '. ',
    textInserted: 'ㅅ',
    insertionOffset: 2,
    selection: TextSelection.collapsed(offset: 3, affinity: TextAffinity.downstream),
    composing: TextRange(start: -1, end: -1),
  ),
]
```

Second batch:

```dart
[
  TextEditingDeltaNonTextUpdate(
    oldText: '. ㅅ',
    selection: TextSelection(baseOffset: 1, extentOffset: 3, isDirectional: false),
    composing: TextRange(start: -1, end: -1),
  ),
  TextEditingDeltaDeletion(
    oldText: '. ㅅ',
    deletedRange: TextRange(start: 1, end: 3),
    selection: TextSelection.collapsed(
      offset: 1,
      affinity: TextAffinity.downstream,
    ),
    composing: TextRange(start: -1, end: -1),
  ),
  TextEditingDeltaInsertion(
    oldText: '.',
    textInserted: ' ',
    insertionOffset: 1,
    selection: TextSelection.collapsed(
      offset: 2,
      affinity: TextAffinity.downstream,
    ),
    composing: TextRange(start: -1, end: -1),
  ),
  TextEditingDeltaInsertion(
    oldText: '. ',
    textInserted: '쇼',
    insertionOffset: 2,
    selection: TextSelection.collapsed(
      offset: 3,
      affinity: TextAffinity.downstream,
    ),
    composing: TextRange(start: -1, end: -1),
  )
]
```

### Code sample

<details><summary>Code sample</summary>

```dart
import 'package:flutter/material.dart';
import 'package:flutter/services.dart';

void main() {
  runApp(
    const MaterialApp(
      home: Scaffold(
        body: TextInputExample(),
      ),
    ),
  );
}

class TextInputExample extends StatefulWidget {
  const TextInputExample({super.key});

  @override
  State<TextInputExample> createState() => _TextInputExampleState();
}

class _TextInputExampleState extends State<TextInputExample> implements DeltaTextInputClient {
  final FocusNode _focusNode = FocusNode();
  final GlobalKey _textKey = GlobalKey();

  TextInputConnection? _inputConnection;
  TextEditingValue _currentEditingValue = const TextEditingValue(
    text: '. ',
    selection: TextSelection.collapsed(offset: 2),
  );

  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addPostFrameCallback((timeStamp) {
      _attach();
    });
  }

  @override
  void dispose() {
    _focusNode.dispose();
    super.dispose();
  }

  @override
  void updateEditingValueWithDeltas(List<TextEditingDelta> textEditingDeltas) {
    print('Received ${textEditingDeltas.length} deltas');
    TextEditingValue newEditingValue = _currentEditingValue;

    for (final delta in textEditingDeltas) {
      print(delta);
      newEditingValue = delta.apply(newEditingValue);
    }

    setState(() {
